    // When the following conditions hold:
    // 1. (C2 - ((C2 & M) - 1)) is a power of 2 (no borrowing across mask boundary)
    // 2. ((C2 + M) & ((C2 & M) - 1)) == ((C2 & M) - 1) (no wrapping issues)
    // 3. Inner sub has nuw OR M is a negated power of 2
    // If additionally C1 == C2 & M, simplify to X & M_Trunc.
    const APInt *C2Val, *MVal;
